      : sql``;
  const deptBonusTerm =
    deptHints.length > 0
      ? sql`+ CASE WHEN db.claim_id IS NOT NULL THEN 0.002 ELSE 0.0 END`
      : sql``;
  const deptBonusJoin =
    deptHints.length > 0
      ? sql`LEFT JOIN dept_bonus db ON db.claim_id = vr.id`
      : sql``;

  const rows = await db.execute<{
    id: string;
    summary: string;
    claim_type: string;
    impact_score: number;
    confidence_score: number;
    distance: number;
    rrf_score: number;
