   1: // D14 — Claim extraction submit task (Batch API path)
   2: //
   3: // Cron: every 4 hours, same as the sync claim-extraction worker. Bails when
   4: // settings.extraction_dispatch_mode !== 'batch'. The sync worker has a
   5: // mirror-image bail when the flag IS 'batch', so the two paths never both
   6: // process the same messages.
   7: //
   8: // Flow:
   9: //   1. Read the flag — bail if not 'batch'
  10: //   2. Resolve the extraction route + check its adapter supports batch
  11: //   3. Pull pending user messages (BATCH_SIZE), mark them 'processing'
  12: //   4. Group into 60-minute conversation segments
  13: //   5. For each segment: compile the prompt plan, insert extraction_batches
  14: //      and oracle_context_packs rows
  15: //   6. Build BatchRequest[] (customId = extraction_batches.id)
  16: //   7. Call adapter.submitBatch — submits the JSONL to OpenAI / GCS for Vertex
  17: //   8. Insert provider_batch_jobs row with the providerBatchId + metadata
  18: //   9. Link all extraction_batches rows to the provider_batch_jobs row
  19: //
  20: // The drain task (claim-extraction-batch-drain.ts) is what runs validation +
  21: // promotion when the batch completes. This task only submits.
  22: 
  23: import { schedules } from '@trigger.dev/sdk/v3';
  24: import { and, eq, inArray } from 'drizzle-orm';
  25: import { createHash } from 'node:crypto';
  26: import { getDirectDb } from '@oracle/db/client';
  27: import {
  28:   employees,
  29:   extractionBatches,
  30:   jobRuns,
  31:   messages,
  32:   oracleContextPacks,
  33:   providerBatchJobs,
  34:   settings,
  35: } from '@oracle/db';
  36: import {
  37:   buildStandardAdapters,
  38:   OracleAIClient,
  39:   supportsBatch,
  40:   zodToJsonSchema,
  41:   makeBlock,
  42:   EXTRACTION_SYSTEM_PROMPT,
  43:   EXTRACTION_PROMPT_VERSION,
  44:   ExtractionOutputSchema,
  45:   formatConversationSegment,
  46:   type BatchRequest,
  47:   type FormattedMessage,
  48: } from '@oracle/ai';
  49: import {
  50:   BATCH_SIZE,
  51:   buildContextPackInsert,
  52:   groupIntoSegments,
  53:   resolveExtractionRoute,
  54: } from './claim-extraction';
  55: 
  56: export interface BatchSubmitTotals {
  57:   ok: boolean;
  58:   skipped: boolean;
  59:   reason?: string;
  60:   segmentsSubmitted: number;
  61:   providerBatchId?: string;
  62: }
  63: 
  64: export async function runClaimExtractionBatchSubmitOnce(
  65:   triggerRunId: string,
  66: ): Promise<BatchSubmitTotals> {
  67:   const db = getDirectDb();
  68:   const startedAt = new Date();
  69: 
  70:   const [jobRun] = await db
  71:     .insert(jobRuns)
  72:     .values({
  73:       triggerRunId,
  74:       jobType: 'claim-extraction-batch-submit',
  75:       status: 'running',
  76:       startedAt,
  77:       inputJson: { batchSize: BATCH_SIZE },
  78:     })
  79:     .returning({ id: jobRuns.id });
  80:   if (!jobRun) throw new Error('[claim-extraction-batch-submit] failed to insert job_runs row');
  81: 
  82:   const finish = async (output: Record<string, unknown>) => {
  83:     await db
  84:       .update(jobRuns)
  85:       .set({ status: 'complete', finishedAt: new Date(), outputJson: output })
  86:       .where(eq(jobRuns.id, jobRun.id));
  87:   };
  88: 
  89:   // Hoisted so the catch can revert messages this run flipped to 'processing'.
  90:   let claimedMessageIds: string[] = [];
  91: 
  92:   try {
  93:     // 1. Dispatch-mode gate — mirror image of the sync worker.
  94:     const dispatchModeRow = await db
  95:       .select({ value: settings.value })
  96:       .from(settings)
  97:       .where(eq(settings.key, 'extraction_dispatch_mode'))
  98:       .limit(1);
  99:     const dispatchMode = (dispatchModeRow[0]?.value as string | undefined) ?? 'sync';
 100:     if (dispatchMode !== 'batch') {
 101:       await finish({ skipped: true, reason: `extraction_dispatch_mode=${dispatchMode}` });
 102:       return { ok: true, skipped: true, reason: `extraction_dispatch_mode=${dispatchMode}`, segmentsSubmitted: 0 };
 103:     }
 104: 
 105:     // 2. Resolve route + check adapter capability.
 106:     const route = await resolveExtractionRoute(db);
 107:     const adapters = buildStandardAdapters();
 108:     const adapter = adapters[route.provider];
 109:     if (!adapter) {
 110:       await finish({ skipped: true, reason: `no adapter registered for provider ${route.provider}` });
 111:       return { ok: true, skipped: true, reason: `no adapter for ${route.provider}`, segmentsSubmitted: 0 };
 112:     }
 113:     if (!supportsBatch(adapter)) {
 114:       await finish({ skipped: true, reason: `adapter ${route.provider} does not implement Batch API` });
 115:       return { ok: true, skipped: true, reason: `adapter ${route.provider} does not support batch`, segmentsSubmitted: 0 };
 116:     }
 117: 
 118:     // 3. Pull pending messages.
 119:     const pendingMessages = await db
 120:       .select({
 121:         id: messages.id,
 122:         channelId: messages.channelId,
 123:         employeeId: messages.employeeId,
 124:         role: messages.role,
 125:         content: messages.content,
 126:         createdAt: messages.createdAt,
 127:         authorName: employees.name,
 128:       })
 129:       .from(messages)
 130:       .leftJoin(employees, eq(employees.id, messages.employeeId))
 131:       .where(and(eq(messages.extractionStatus, 'pending'), eq(messages.role, 'user')))
 132:       .orderBy(messages.createdAt)
 133:       .limit(BATCH_SIZE);
 134: 
 135:     if (pendingMessages.length === 0) {
 136:       await finish({ segmentsSubmitted: 0, reason: 'no pending messages' });
 137:       return { ok: true, skipped: false, segmentsSubmitted: 0 };
 138:     }
 139: 
 140:     // 4. Mark as 'processing' for idempotency.
 141:     const messageIds = pendingMessages.map((m) => m.id);
 142:     claimedMessageIds = messageIds;
 143:     await db
 144:       .update(messages)
 145:       .set({ extractionStatus: 'processing' })
 146:       .where(inArray(messages.id, messageIds));
 147: 
 148:     // 5. Group into segments + 6. Build extraction_batches + context_packs + BatchRequest list.
 149:     const segments = groupIntoSegments(pendingMessages);
 150:     const client = new OracleAIClient({ adapters, fallbackOnError: false });
 151:     const requests: BatchRequest[] = [];
 152:     const stagedBatchIds: string[] = [];
 153:     const allMessageIdsForFailure: string[] = [];
 154: 
 155:     for (const segment of segments) {
 156:       const segmentIds = segment.map((m) => m.id);
 157:       allMessageIdsForFailure.push(...segmentIds);
 158:       const userMessages = segment.filter((m) => m.role === 'user');
 159:       if (userMessages.length === 0) {
 160:         // Skip empty segments at submit time — mark messages as 'skipped'.
 161:         await db
 162:           .update(messages)
 163:           .set({ extractionStatus: 'skipped', extractedAt: new Date() })
 164:           .where(inArray(messages.id, segmentIds));
 165:         continue;
 166:       }
 167: 
 168:       const formatted = formatConversationSegment(segment);
 169:       const blocks = [
 170:         makeBlock({
 171:           id: 'extraction-system',
 172:           label: 'Extraction system prompt',
 173:           kind: 'stable_system',
 174:           content: EXTRACTION_SYSTEM_PROMPT,
 175:           reasonIncluded: 'extraction prompt v' + EXTRACTION_PROMPT_VERSION,
 176:         }),
 177:         makeBlock({
 178:           id: 'segment',
 179:           label: 'Conversation segment to extract from',
 180:           kind: 'dynamic_input',
 181:           content: formatted,
 182:           reasonIncluded: `segment of ${segment.length} message(s) in this batch`,
 183:         }),
 184:       ];
 185:       const plan = client.compile({
 186:         taskType: 'message_claim_extraction',
 187:         routeId: route.routeId,
 188:         promptVersion: EXTRACTION_PROMPT_VERSION,
 189:         blocks,
 190:         observability: { includedMessageIds: segmentIds },
 191:       });
 192:       const sourceHash = createHash('sha256').update(formatted, 'utf8').digest('hex');
 193: 
 194:       // Stage extraction_batches row in pending_model status (no model_run_id
 195:       // yet — that gets filled in at drain time when results come back).
 196:       const [batch] = await db
 197:         .insert(extractionBatches)
 198:         .values({
 199:           jobRunId: jobRun.id,
 200:           batchType: 'message_segment',
 201:           status: 'pending_model',
 202:           sourceMessageIds: segmentIds,
 203:           sourceHash,
 204:           modelRunIdsAttempted: [],
 205:           routeIdsAttempted: [route.routeId],
 206:         })
 207:         .returning({ id: extractionBatches.id });
 208:       if (!batch) throw new Error('[batch-submit] failed to insert extraction_batches row');
 209: 
 210:       const [contextPack] = await db
 211:         .insert(oracleContextPacks)
 212:         .values(buildContextPackInsert(plan))
 213:         .returning({ id: oracleContextPacks.id });
 214:       if (!contextPack) throw new Error('[batch-submit] failed to insert oracle_context_packs row');
 215: 
 216:       await db
 217:         .update(extractionBatches)
 218:         .set({ contextPackId: contextPack.id })
 219:         .where(eq(extractionBatches.id, batch.id));
 220: 
 221:       stagedBatchIds.push(batch.id);
 222:       requests.push({
 223:         customId: batch.id, // extraction_batches.id IS the customId so drain can map results
