 225:       });
 226:     }
 227: 
 228:     if (requests.length === 0) {
 229:       await finish({ segmentsSubmitted: 0, reason: 'all segments were user-message-free; no batch submitted' });
 230:       return { ok: true, skipped: false, segmentsSubmitted: 0 };
 231:     }
 232: 
 233:     // 7. Submit batch via adapter.
 234:     const jsonSchema = zodToJsonSchema(ExtractionOutputSchema);
 235:     const submitResult = await adapter.submitBatch!({
 236:       route,
 237:       requests,
 238:       jsonSchema,
 239:     });
 240: 
 241:     // 8. Insert provider_batch_jobs row.
 242:     const [batchJob] = await db
 243:       .insert(providerBatchJobs)
 244:       .values({
 245:         provider: route.provider,
 246:         providerBatchId: submitResult.providerBatchId,
 247:         status: 'submitted',
 248:         taskType: 'message_claim_extraction',
 249:         routeId: route.routeId,
 250:         modelId: route.modelId,
 251:         requestCount: requests.length,
 252:         providerMetadataJson: submitResult.providerMetadata,
 253:       })
 254:       .returning({ id: providerBatchJobs.id });
 255:     if (!batchJob) throw new Error('[batch-submit] failed to insert provider_batch_jobs row');
 256: 
 257:     // 9. Link extraction_batches rows to the batch job.
 258:     await db
 259:       .update(extractionBatches)
 260:       .set({ providerBatchJobId: batchJob.id })
 261:       .where(inArray(extractionBatches.id, stagedBatchIds));
 262: 
 263:     await finish({
 264:       segmentsSubmitted: requests.length,
 265:       providerBatchId: submitResult.providerBatchId,
 266:       providerBatchJobId: batchJob.id,
 267:     });
 268:     return {
 269:       ok: true,
 270:       skipped: false,
 271:       segmentsSubmitted: requests.length,
 272:       providerBatchId: submitResult.providerBatchId,
 273:     };
 274:   } catch (err) {
 275:     // On any failure during submit, revert the messages this run claimed back
 276:     // to 'pending' so the next cron tick retries them. Only revert rows still
 277:     // in 'processing' — segments we explicitly marked 'skipped' (empty user
 278:     // content) stay skipped. extraction_batches rows we already inserted are
 279:     // left in pending_model and will be reaped by the drain task once it
 280:     // notices they have no provider_batch_job_id link.
 281:     const errMsg = err instanceof Error ? err.message : String(err);
 282:     if (claimedMessageIds.length > 0) {
 283:       try {
 284:         await db
 285:           .update(messages)
 286:           .set({ extractionStatus: 'pending' })
 287:           .where(
 288:             and(
 289:               inArray(messages.id, claimedMessageIds),
 290:               eq(messages.extractionStatus, 'processing'),
 291:             ),
 292:           );
 293:       } catch (revertErr) {
 294:         console.error(
 295:           '[claim-extraction-batch-submit] failed to revert messages to pending',
 296:           revertErr,
 297:         );
 298:       }
 299:     }
 300:     await db
 301:       .update(jobRuns)
 302:       .set({ status: 'failed', finishedAt: new Date(), error: errMsg })
 303:       .where(eq(jobRuns.id, jobRun.id));
 304:     throw err;
 305:   }
 306: }
