   1: // D14 — Claim extraction submit task (Batch API path)
   2: //
   3: // Cron: every 4 hours, same as the sync claim-extraction worker. Bails when
   4: // settings.extraction_dispatch_mode !== 'batch'. The sync worker has a
   5: // mirror-image bail when the flag IS 'batch', so the two paths never both
   6: // process the same messages.
   7: //
   8: // Flow:
   9: //   1. Read the flag — bail if not 'batch'
  10: //   2. Resolve the extraction route + check its adapter supports batch
  11: //   3. Pull pending user messages (BATCH_SIZE), mark them 'processing'
  12: //   4. Group into 60-minute conversation segments
  13: //   5. For each segment: compile the prompt plan, insert extraction_batches
  14: //      and oracle_context_packs rows
  15: //   6. Build BatchRequest[] (customId = extraction_batches.id)
  16: //   7. Call adapter.submitBatch — submits the JSONL to OpenAI / GCS for Vertex
  17: //   8. Insert provider_batch_jobs row with the providerBatchId + metadata
  18: //   9. Link all extraction_batches rows to the provider_batch_jobs row
  19: //
  20: // The drain task (claim-extraction-batch-drain.ts) is what runs validation +
  21: // promotion when the batch completes. This task only submits.
  22: 
  23: import { schedules } from '@trigger.dev/sdk/v3';
  24: import { and, eq, inArray } from 'drizzle-orm';
  25: import { createHash } from 'node:crypto';
  26: import { getDirectDb } from '@oracle/db/client';
  27: import {
  28:   employees,
  29:   extractionBatches,
  30:   jobRuns,
  31:   messages,
  32:   oracleContextPacks,
  33:   providerBatchJobs,
  34:   settings,
  35: } from '@oracle/db';
  36: import {
  37:   buildStandardAdapters,
  38:   OracleAIClient,
  39:   supportsBatch,
  40:   zodToJsonSchema,
  41:   makeBlock,
  42:   EXTRACTION_SYSTEM_PROMPT,
  43:   EXTRACTION_PROMPT_VERSION,
  44:   ExtractionOutputSchema,
  45:   formatConversationSegment,
  46:   type BatchRequest,
  47:   type FormattedMessage,
  48: } from '@oracle/ai';
  49: import {
  50:   BATCH_SIZE,
  51:   buildContextPackInsert,
  52:   groupIntoSegments,
  53:   resolveExtractionRoute,
  54: } from './claim-extraction';
  55: 
  56: export interface BatchSubmitTotals {
  57:   ok: boolean;
  58:   skipped: boolean;
  59:   reason?: string;
  60:   segmentsSubmitted: number;
  61:   providerBatchId?: string;
  62: }
  63: 
  64: export async function runClaimExtractionBatchSubmitOnce(
  65:   triggerRunId: string,
  66: ): Promise<BatchSubmitTotals> {
  67:   const db = getDirectDb();
  68:   const startedAt = new Date();
  69: 
  70:   const [jobRun] = await db
  71:     .insert(jobRuns)
  72:     .values({
  73:       triggerRunId,
  74:       jobType: 'claim-extraction-batch-submit',
  75:       status: 'running',
  76:       startedAt,
  77:       inputJson: { batchSize: BATCH_SIZE },
  78:     })
  79:     .returning({ id: jobRuns.id });
  80:   if (!jobRun) throw new Error('[claim-extraction-batch-submit] failed to insert job_runs row');
  81: 
  82:   const finish = async (output: Record<string, unknown>) => {
  83:     await db
  84:       .update(jobRuns)
  85:       .set({ status: 'complete', finishedAt: new Date(), outputJson: output })
  86:       .where(eq(jobRuns.id, jobRun.id));
  87:   };
  88: 
  89:   // Hoisted so the catch can roll back the state this run created.
  90:   // - claimedMessageIds: messages we flipped 'pending' → 'processing'.
  91:   // - stagedBatchIds / stagedContextPackIds: extraction_batches +
  92:   //   oracle_context_packs rows we inserted as part of staging segments.
  93:   // - providerAccepted: flipped to true the moment adapter.submitBatch returns
  94:   //   successfully. If a failure happens after that, the batch is live at the
  95:   //   provider and the staging rows are still needed (drain finds them by
  96:   //   customId from the batch result, not by provider_batch_job_id), so we
  97:   //   leave them in place and log loudly instead of cleaning up.
  98:   let claimedMessageIds: string[] = [];
  99:   const stagedBatchIds: string[] = [];
 100:   const stagedContextPackIds: string[] = [];
 101:   let providerAccepted = false;
 102:   let providerBatchIdForRecovery: string | null = null;
 103: 
 104:   try {
 105:     // 1. Dispatch-mode gate — mirror image of the sync worker.
 106:     const dispatchModeRow = await db
 107:       .select({ value: settings.value })
 108:       .from(settings)
 109:       .where(eq(settings.key, 'extraction_dispatch_mode'))
 110:       .limit(1);
 111:     const dispatchMode = (dispatchModeRow[0]?.value as string | undefined) ?? 'sync';
 112:     if (dispatchMode !== 'batch') {
 113:       await finish({ skipped: true, reason: `extraction_dispatch_mode=${dispatchMode}` });
 114:       return { ok: true, skipped: true, reason: `extraction_dispatch_mode=${dispatchMode}`, segmentsSubmitted: 0 };
 115:     }
 116: 
 117:     // 2. Resolve route + check adapter capability.
 118:     const route = await resolveExtractionRoute(db);
 119:     const adapters = buildStandardAdapters();
 120:     const adapter = adapters[route.provider];
 121:     if (!adapter) {
 122:       await finish({ skipped: true, reason: `no adapter registered for provider ${route.provider}` });
 123:       return { ok: true, skipped: true, reason: `no adapter for ${route.provider}`, segmentsSubmitted: 0 };
 124:     }
 125:     if (!supportsBatch(adapter)) {
 126:       await finish({ skipped: true, reason: `adapter ${route.provider} does not implement Batch API` });
 127:       return { ok: true, skipped: true, reason: `adapter ${route.provider} does not support batch`, segmentsSubmitted: 0 };
 128:     }
 129: 
 130:     // 3. Pull pending messages.
 131:     const pendingMessages = await db
 132:       .select({
 133:         id: messages.id,
 134:         channelId: messages.channelId,
 135:         employeeId: messages.employeeId,
 136:         role: messages.role,
 137:         content: messages.content,
 138:         createdAt: messages.createdAt,
 139:         authorName: employees.name,
 140:       })
 141:       .from(messages)
 142:       .leftJoin(employees, eq(employees.id, messages.employeeId))
 143:       .where(and(eq(messages.extractionStatus, 'pending'), eq(messages.role, 'user')))
 144:       .orderBy(messages.createdAt)
 145:       .limit(BATCH_SIZE);
 146: 
 147:     if (pendingMessages.length === 0) {
 148:       await finish({ segmentsSubmitted: 0, reason: 'no pending messages' });
 149:       return { ok: true, skipped: false, segmentsSubmitted: 0 };
 150:     }
 151: 
 152:     // 4. Mark as 'processing' for idempotency.
 153:     const messageIds = pendingMessages.map((m) => m.id);
 154:     claimedMessageIds = messageIds;
 155:     await db
 156:       .update(messages)
 157:       .set({ extractionStatus: 'processing' })
 158:       .where(inArray(messages.id, messageIds));
 159: 
 160:     // 5. Group into segments + 6. Build extraction_batches + context_packs + BatchRequest list.
 161:     const segments = groupIntoSegments(pendingMessages);
 162:     const client = new OracleAIClient({ adapters, fallbackOnError: false });
 163:     const requests: BatchRequest[] = [];
 164:     const allMessageIdsForFailure: string[] = [];
 165: 
 166:     for (const segment of segments) {
 167:       const segmentIds = segment.map((m) => m.id);
 168:       allMessageIdsForFailure.push(...segmentIds);
 169:       const userMessages = segment.filter((m) => m.role === 'user');
 170:       if (userMessages.length === 0) {
 171:         // Skip empty segments at submit time — mark messages as 'skipped'.
 172:         await db
 173:           .update(messages)
 174:           .set({ extractionStatus: 'skipped', extractedAt: new Date() })
 175:           .where(inArray(messages.id, segmentIds));
 176:         continue;
 177:       }
 178: 
 179:       const formatted = formatConversationSegment(segment);
 180:       const blocks = [
 181:         makeBlock({
 182:           id: 'extraction-system',
 183:           label: 'Extraction system prompt',
 184:           kind: 'stable_system',
 185:           content: EXTRACTION_SYSTEM_PROMPT,
 186:           reasonIncluded: 'extraction prompt v' + EXTRACTION_PROMPT_VERSION,
 187:         }),
 188:         makeBlock({
 189:           id: 'segment',
 190:           label: 'Conversation segment to extract from',
 191:           kind: 'dynamic_input',
 192:           content: formatted,
 193:           reasonIncluded: `segment of ${segment.length} message(s) in this batch`,
 194:         }),
 195:       ];
 196:       const plan = client.compile({
 197:         taskType: 'message_claim_extraction',
 198:         routeId: route.routeId,
 199:         promptVersion: EXTRACTION_PROMPT_VERSION,
 200:         blocks,
 201:         observability: { includedMessageIds: segmentIds },
 202:       });
 203:       const sourceHash = createHash('sha256').update(formatted, 'utf8').digest('hex');
 204: 
 205:       // Stage extraction_batches row in pending_model status (no model_run_id
 206:       // yet — that gets filled in at drain time when results come back).
 207:       const [batch] = await db
 208:         .insert(extractionBatches)
 209:         .values({
 210:           jobRunId: jobRun.id,
 211:           batchType: 'message_segment',
 212:           status: 'pending_model',
 213:           sourceMessageIds: segmentIds,
 214:           sourceHash,
 215:           modelRunIdsAttempted: [],
 216:           routeIdsAttempted: [route.routeId],
 217:         })
 218:         .returning({ id: extractionBatches.id });
 219:       if (!batch) throw new Error('[batch-submit] failed to insert extraction_batches row');
 220:       // Track for rollback immediately — if the context_pack insert below
 221:       // throws, this row is already orphaned and the catch needs to delete it.
 222:       stagedBatchIds.push(batch.id);
 223: 
 224:       const [contextPack] = await db
 225:         .insert(oracleContextPacks)
 226:         .values(buildContextPackInsert(plan))
 227:         .returning({ id: oracleContextPacks.id });
 228:       if (!contextPack) throw new Error('[batch-submit] failed to insert oracle_context_packs row');
 229:       stagedContextPackIds.push(contextPack.id);
 230: 
 231:       await db
 232:         .update(extractionBatches)
 233:         .set({ contextPackId: contextPack.id })
 234:         .where(eq(extractionBatches.id, batch.id));
