 242:     if (requests.length === 0) {
 243:       await finish({ segmentsSubmitted: 0, reason: 'all segments were user-message-free; no batch submitted' });
 244:       return { ok: true, skipped: false, segmentsSubmitted: 0 };
 245:     }
