 260:     // 8. Insert provider_batch_jobs row.
 261:     const [batchJob] = await db
 262:       .insert(providerBatchJobs)
 263:       .values({
 264:         provider: route.provider,
 265:         providerBatchId: submitResult.providerBatchId,
 266:         status: 'submitted',
 267:         taskType: 'message_claim_extraction',
 268:         routeId: route.routeId,
 269:         modelId: route.modelId,
 270:         requestCount: requests.length,
 271:         providerMetadataJson: submitResult.providerMetadata,
 272:       })
 273:       .returning({ id: providerBatchJobs.id });
 274:     if (!batchJob) throw new Error('[batch-submit] failed to insert provider_batch_jobs row');
 275: 
 276:     // 9. Link extraction_batches rows to the batch job.
 277:     await db
 278:       .update(extractionBatches)
 279:       .set({ providerBatchJobId: batchJob.id })
 280:       .where(inArray(extractionBatches.id, stagedBatchIds));
 281: 
 282:     await finish({
 283:       segmentsSubmitted: requests.length,
 284:       providerBatchId: submitResult.providerBatchId,
 285:       providerBatchJobId: batchJob.id,
 286:     });
 287:     return {
 288:       ok: true,
 289:       skipped: false,
 290:       segmentsSubmitted: requests.length,
 291:       providerBatchId: submitResult.providerBatchId,
 292:     };
 293:   } catch (err) {
 294:     const errMsg = err instanceof Error ? err.message : String(err);
 295: 
 296:     // Two failure regimes:
 297:     //
 298:     //  (a) providerAccepted === false: the failure happened before the
 299:     //      provider accepted the batch. Nothing is live upstream. Roll back
 300:     //      everything this run created — messages back to pending, staged
 301:     //      extraction_batches + oracle_context_packs deleted — so the next
 302:     //      cron tick gets a clean retry and the admin observability surface
 303:     //      isn't littered with stale pending_model rows that will never get
 304:     //      drained.
 305:     //
 306:     //  (b) providerAccepted === true: the provider has the batch. A failure
 307:     //      between submitBatch and the back-link update means messages stay
 308:     //      'processing' (drain will mark them based on the batch result) and
 309:     //      the staging rows MUST be kept — drain looks them up by customId
 310:     //      from the batch result, not by the back-link. We log loudly so an
 311:     //      operator can investigate any state mismatch.
 312:     if (!providerAccepted) {
 313:       if (claimedMessageIds.length > 0) {
 314:         try {
 315:           await db
 316:             .update(messages)
 317:             .set({ extractionStatus: 'pending' })
 318:             .where(
 319:               and(
 320:                 inArray(messages.id, claimedMessageIds),
 321:                 eq(messages.extractionStatus, 'processing'),
 322:               ),
 323:             );
 324:         } catch (revertErr) {
 325:           console.error(
 326:             '[claim-extraction-batch-submit] failed to revert messages to pending',
 327:             revertErr,
 328:           );
 329:         }
 330:       }
 331:       // Delete the FK child first (oracle_context_packs is referenced from
 332:       // extraction_batches.context_pack_id), then the parent staging rows.
 333:       // Both deletes are scoped to ids this run created, so they cannot
 334:       // touch any other batch's state.
 335:       if (stagedBatchIds.length > 0) {
 336:         try {
 337:           await db
 338:             .delete(extractionBatches)
 339:             .where(inArray(extractionBatches.id, stagedBatchIds));
 340:         } catch (cleanupErr) {
 341:           console.error(
 342:             '[claim-extraction-batch-submit] failed to delete staged extraction_batches rows',
 343:             cleanupErr,
 344:           );
 345:         }
 346:       }
 347:       if (stagedContextPackIds.length > 0) {
 348:         try {
 349:           await db
 350:             .delete(oracleContextPacks)
 351:             .where(inArray(oracleContextPacks.id, stagedContextPackIds));
 352:         } catch (cleanupErr) {
 353:           console.error(
 354:             '[claim-extraction-batch-submit] failed to delete staged oracle_context_packs rows',
 355:             cleanupErr,
 356:           );
 357:         }
 358:       }
 359:     } else {
 360:       console.error(
 361:         '[claim-extraction-batch-submit] failure after provider accepted batch — staging rows + messages left as-is for drain or manual recovery',
 362:         {
 363:           providerBatchId: providerBatchIdForRecovery,
 364:           stagedBatchIds,
 365:           stagedContextPackIds,
 366:           claimedMessageCount: claimedMessageIds.length,
 367:           error: errMsg,
 368:         },
 369:       );
 370:     }
 371: 
 372:     await db
 373:       .update(jobRuns)
 374:       .set({ status: 'failed', finishedAt: new Date(), error: errMsg })
 375:       .where(eq(jobRuns.id, jobRun.id));
 376:     throw err;
 377:   }
 378: }
 379: 
 380: export const claimExtractionBatchSubmitTask = schedules.task({
 381:   id: 'claim-extraction-batch-submit',
 382:   cron: '0 */4 * * *',
 383:   maxDuration: 60 * 5,
 384:   run: async (_payload, { ctx }) => {
 385:     return runClaimExtractionBatchSubmitOnce(ctx.run.id);
 386:   },
 387: });
